const items = $input.all();
const cleanedData = items.map((item) => {
  const cleanedItem = { ...item.json };

  // Convert StudentID to number
  cleanedItem.StudentID = Number(cleanedItem.StudentID);

  // Convert Gender to lowercase
  cleanedItem.Gender = cleanedItem.Gender.toLowerCase();

  // Convert Location to title case
  cleanedItem.Location =
    cleanedItem.Location.charAt(0).toUpperCase() +
    cleanedItem.Location.slice(1).toLowerCase();

  // Convert EnrollmentDate, LastLogin, and PurchaseDate to Date
  cleanedItem.EnrollmentDate = new Date(cleanedItem.EnrollmentDate);
  cleanedItem.LastLogin = new Date(cleanedItem.LastLogin);
  cleanedItem.PurchaseDate = new Date(cleanedItem.PurchaseDate);

  // Convert PaymentAmount to number and round to 2 decimal places
  cleanedItem.PaymentAmount = Number(cleanedItem.PaymentAmount).toFixed(2);

  // Convert Renewed to boolean
  cleanedItem.Renewed = cleanedItem.Renewed.toLowerCase() === "yes";

  return cleanedItem;
});

return cleanedData;

const items = $input.all().map((item) => item.json);

const totalStudents = items.length;

const totalVideosWatched = items.reduce(
  (sum, item) => sum + item.VideosWatched,
  0,
);

const totalAssignmentsSubmitted = items.reduce(
  (sum, items) => sum + (Number(items.AssignmentsSubmitted) || 0),
  0
);

const avgQuizScore =
  items.reduce((sum, item) => sum + item.QuizScoresAvg, 0) / totalStudents;

const avgSessionTime =
  items.reduce((sum, item) => sum + item.AvgSessionTime, 0) / totalStudents;

const renewedSubscriptions = items.filter((item) => item.Renewed).length;

const studentsByLocation = items.reduce((grouped, item) => {
  grouped[item.Location] = (grouped[item.Location] || 0) + 1;
  return grouped;
}, {});

return {
  totalStudents,
  totalVideosWatched,
  totalAssignmentsSubmitted,
  avgQuizScore,
  avgSessionTime,
  renewedSubscriptions,
  studentsByLocation,
};

