// 1️⃣ Grab all incoming items
const items = $input.all();

// 2️⃣ Prepare containers
let summaryText = '';
const charts = [];

// 3️⃣ Loop over each item just once
for (const item of items) {
  const data = item.json;

  // Capture the first summary block found
  if (data.text && !summaryText) {
    summaryText = data.text.trim();
  }
  // If it's a chart block, collect URL + auto-ID
  else if (data.url) {
    // Try to pick a unique part of the chart URL for captioning
    const chartId =
      data.url.match(/(sf|zf)-[\w-]+/)?.[0] || `chart-${charts.length + 1}`;
    charts.push({
      caption: `Chart ${charts.length + 1} (${chartId})`,
      imageUrl: data.url
    });
  }
}

// 4️⃣ Fallback summary if none was provided
if (!summaryText) {
  summaryText = "No summary provided.";
}

// 5️⃣ Compose the HTML for each chart
const chartBlocks = charts
  .map(
    chart => `
  <div class="chart-block">
    <h3>${chart.caption}</h3>
    <img src="${chart.imageUrl}" alt="${chart.caption}" />
  </div>
`
  )
  .join("\n");

// 6️⃣ Full HTML report document
const html = `
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <title>📊 Student Engagement Report</title>
  <style>
    body {
      font-family: 'Segoe UI', sans-serif;
      background: #f5f7fa;
      margin: 0;
      padding: 30px;
      color: #222;
    }
    h1 {
      color: #2c3e50;
      text-align: center;
      margin-bottom: 30px;
    }
    .summary-box {
      background: #fffefc;
      border-left: 5px solid #ffa500;
      padding: 20px 25px;
      border-radius: 8px;
      max-width: 900px;
      margin: 0 auto 40px auto;
      box-shadow: 0 2px 8px rgba(0,0,0,0.05);
      font-size: 1.05em;
    }
    .charts {
      display: flex;
      flex-wrap: wrap;
      justify-content: center;
      gap: 24px;
    }
    .chart-block {
      background: #fff;
      border-radius: 10px;
      box-shadow: 0 2px 6px rgba(0,0,0,0.1);
      padding: 16px;
      text-align: center;
      width: 100%;
      max-width: 360px;
    }
    .chart-block img {
      max-width: 100%;
      border-radius: 6px;
      border: 1px solid #ccc;
    }
    footer {
      text-align: center;
      font-size: 0.85em;
      color: #666;
      margin-top: 50px;
    }
  </style>
</head>
<body>
  <h1>📊 Student Engagement Report</h1>
  <div class="summary-box"><p>${summaryText}</p></div>
  <div class="charts">${chartBlocks}</div>
  <footer>Generated on ${new Date().toLocaleString()}</footer>
</body>
</html>
`;

// 7️⃣ Return exactly one item containing the full report
return [
  {
    json: {
      html
    }
  }
];

